 */

const maxChildren = 4
const maxDepth = 2
function layoutChildren(currentDepth: number) {
    const children = []

    for (let i = 0; i < maxChildren; i++) {
        children.push(
            <motion.div
                layout
                key={i}
                style={{
                    display: "flex",
                    alignItems: "stretch",
                    justifyContent: "stretch",
                    backgroundColor:
                        currentDepth === 0
                            ? "red"
                            : currentDepth === 1
                            ? "blue"
                            : "green",
                    width: "25%",
                    height: "25%",
                }}
            >
                {currentDepth < maxDepth && layoutChildren(currentDepth + 1)}
            </motion.div>
        )
    }

    return children
}

