const Cell = ({ center, i, onClick }) => {
    const x = col(i)
    const y = row(i)
    const d = distance2D({ x, y }, center)
    const n = Math.max(d / max, 0.05) // normalized

    const animation = useAnimation()

    const animate = async () => {
        await animation.start({
            scale: 1,
            y: 0,
            opacity: 1,
            transition: { duration: 0.15 },
        })

        await animation.start({
            scale: Math.min(1, 0.2 + n),
            y: Math.max(0, (0.5 - n) * 50),
            opacity: 0.5,
            transition: {
                delay: d * stagger,
                type: "tween",
                ease: "easeInOut",
                duration: 0.5,
                repeat: Infinity,
                repeatType: "reverse",
            },
        })
    }

    useEffect(() => {
        animate()
    })

    return (
        <div style={{ height: "100%", width: "100%" }} onClick={onClick}>
            <motion.div
                style={{
                    height: "100%",
                    width: "100%",
                    borderRadius: "50%",
                    background: "white",
                }}
                animate={animation}
                key={`cell_${i}`}
            />
        </div>
    )
}

