export const App = () => {
    const svgRef = useRef<SVGSVGElement>(null)

    return (
        <MotionConfig transformPagePoint={transformViewBoxPoint(svgRef)}>
            <svg
                ref={svgRef}
                viewBox="0 0 100 100"
                style={{
                    width: 500,
                    height: 500,
                    border: "2px solid white",
                    borderRadius: 20,
