                    <motion.div
                        key="b"
                        initial={{
                            opacity: 0,
                        }}
                        animate={{
                            opacity: 1,
                        }}
                        exit={{
                            opacity: 0,
                        }}
                        transition={{
                            duration: 1,
                        }}
                        style={styleB}
                    >
                        B
                    </motion.div>
                )}
            </AnimatePresence>
            <button onClick={() => setToggle((prev) => !prev)}>Switch</button>
        </MotionConfig>
    )
