    const opacity = useTransform(
        scrollY,
        [elementTop, elementTop + 600],
        [1, 0]
    )

    useEffect(() => {
        const log = () => {
            console.log(elementTop, scrollY.get(), opacity.get())
        }
        window.addEventListener("scroll", log)
        return () => window.removeEventListener("scroll", log)
    }, [elementTop, scrollY, opacity])

    return (
        <>
            <div
                style={{
                    height: "400vh",
                    backgroundColor: "lightblue",
                }}
            />
            <div
                ref={ref}
                style={{
                    height: "200vh",
                    width: "100vw",
                }}
            >
                <motion.div
                    initial={{ background: "#f9cb29" }}
                    style={{
                        opacity,
                    }}
                >
                    <div
                        style={{
                            display: "flex",
                            flexDirection: "column",
                            alignItems: "center",
                            justifyContent: "center",
                            textAlign: "center",
                            width: "100%",
                            height: "100vh",
                            position: "relative",
                        }}
                    >
                        Hi!
                    </div>
                </motion.div>
            </div>
        </>
    )
}

import {
    motion,
    useMotionValue,
    useVelocity,
    useMotionValueEvent,
    frameData,
} from "framer-motion"

export const App = () => {
    const x = useMotionValue(0)
    const xVelocity = useVelocity(x)
    const xAcceleration = useVelocity(xVelocity)

    useMotionValueEvent(x, "change", (v: number) =>
        console.log("x", Math.round(v), "at", Math.round(frameData.timestamp))
    )

    useMotionValueEvent(xVelocity, "change", (v: number) =>
        console.log(
            "x velocity",
            Math.round(v),
            "at",
            Math.round(frameData.timestamp)
        )
    )

    useMotionValueEvent(xAcceleration, "change", (v: number) =>
        console.log(
            "x acceleration",
            Math.round(v),
            "at",
            Math.round(frameData.timestamp)
        )
    )

    return (
        <motion.div
            animate={{ x: 100 }}
            transition={{ duration: 1, ease: "linear" }}
            style={{ x, width: 100, height: 100, background: "red" }}
        />
    )
}

import { useEffect, useState } from "react"
import {
    mix,
    motion,
    useViewportScroll,
    useSpring,
    useTransform,
} from "framer-motion"

const randomInt = (min, max) => Math.round(mix(min, max, Math.random()))
const generateParagraphLength = () => randomInt(10, 40)
const generateWordLength = () => randomInt(20, 100)

// Randomly generate some paragraphs of word lengths
const paragraphs = Array.from(Array(40)).map(() => {
    return Array.from(Array(generateParagraphLength())).map(generateWordLength)
})

const Word = ({ width }) => <div className="word" style={{ width }} />

